"""Disk-backed function cache with TTL support and thread safety.

Usage:
    @disk_cache(cache_dir="./cache", ttl=3600)
    def my_function(x: int) -> int: ...

    # Or as a class
    cache = DiskCache(cache_dir="./cache", ttl=3600)
    @cache
    def another_function(x: int) -> int: ...

    # Invalidate all cached results
    my_function.cache.clear()
"""

import hashlib
import json
import os
import time
import threading
from functools import wraps

__all__ = ["DiskCache", "disk_cache"]


class DiskCache:
    """Disk-backed cache for function return values.

    Thread-safe via a per-instance lock.  Cache keys are derived from the
    function name and the ``repr`` of positional and keyword arguments,
    hashed with SHA-256 for filesystem-safe filenames.
    """

    def __init__(self, cache_dir: str = "./cache", ttl: int = 3600) -> None:
        self.cache_dir = cache_dir
        self.ttl = ttl
        self._lock = threading.Lock()
        os.makedirs(self.cache_dir, exist_ok=True)

    # ------------------------------------------------------------------
    # internal helpers
    # ------------------------------------------------------------------

    def _make_key(self, func, args, kwargs) -> str:
        """Produce a stable, filesystem-safe key from call arguments."""
        raw = func.__name__ + repr(args) + repr(kwargs)
        return hashlib.sha256(raw.encode("utf-8")).hexdigest()

    def _key_path(self, key: str) -> str:
        return os.path.join(self.cache_dir, f"{key}.json")

    def _get(self, key: str):
        """Return the cached result or *None* after TTL check.

        Expired or corrupt cache files are silently removed.
        """
        path = self._key_path(key)
        if not os.path.isfile(path):
            return None
        try:
            with open(path, encoding="utf-8") as fh:
                data = json.load(fh)
        except (json.JSONDecodeError, OSError):
            return None
        if self.ttl > 0 and time.time() - data.get("ts", 0) > self.ttl:
            try:
                os.remove(path)
            except OSError:
                pass
            return None
        return data.get("result")

    def _put(self, key: str, result) -> None:
        """Persist *result* to disk.

        Values that cannot be serialized to JSON are silently skipped so
        the decorator degrades gracefully rather than raising on cache
        writes.
        """
        path = self._key_path(key)
        try:
            payload = json.dumps({"result": result, "ts": time.time()})
        except (TypeError, ValueError):
            return
        try:
            with open(path, "w", encoding="utf-8") as fh:
                fh.write(payload)
        except OSError:
            pass

    # ------------------------------------------------------------------
    # public API
    # ------------------------------------------------------------------

    def clear(self) -> None:
        """Remove every cached entry in *cache_dir*."""
        with self._lock:
            for name in os.listdir(self.cache_dir):
                if name.endswith(".json"):
                    try:
                        os.remove(os.path.join(self.cache_dir, name))
                    except OSError:
                        pass

    def __call__(self, func):
        """Decorate *func* so its results are cached on disk."""

        @wraps(func)
        def wrapper(*args, **kwargs):
            key = self._make_key(func, args, kwargs)
            with self._lock:
                cached = self._get(key)
            if cached is not None:
                return cached
            result = func(*args, **kwargs)
            with self._lock:
                self._put(key, result)
            return result

        wrapper.cache = self  # expose for manual clear()
        return wrapper


def disk_cache(cache_dir: str = "./cache", ttl: int = 3600):
    """Convenience decorator factory.

    Equivalent to::

        cache = DiskCache(cache_dir=cache_dir, ttl=ttl)
        @cache
        def func(...): ...
    """
    cache = DiskCache(cache_dir=cache_dir, ttl=ttl)

    def decorator(func):
        return cache(func)

    return decorator
